package jfhex;

import java.awt.*;
import java.awt.event.*;
import java.awt.datatransfer.*;/src/jfhex/ASCII8.java
package jfhex;

public class ASCII8 {
  public static char convert(char ch) {
    if ((ch >= 0x80) && (ch <= 0x9f)) return (char)(ch - 0x80 + 0x20);
    if ((ch >= 0xe0) && (ch <= 0xff)) return (char)(ch - 0xe0 + 0x40);
    return ch;
  }
}
