  }

  public <T extends SorobanPayloadable> Single<T> loopUntilReplyTyped(
      String requestId, Class<T> typeReply) {
    return loopUntilReply(requestId)
       .map(untypedPayload -> untypedPayload.read(typeReply));
  }

  public Single<AckResponse> loopUntilReplyAck(String requestId) {
    return loopUntilReplyAck(sorobanClient -> Single.just(requestId));
  }

  public Single<AckResponse> loopUntilReplyAck(CallbackWithArg<SorobanClient, Single<String>> sendRequestOrNull) {
    return loopUntilReply(sendRequestOrNull)
       .map(untypedPayload -> untypedPayload.read(AckResponse.class));
  }

  public <T> Single<T> loopUntilReply(
      CallbackWithArg<SorobanClient, Single<AbstractSorobanEndpoint<T>>> sendRequestOrNull) {
    return rpcSession.loopUntil(
        // send request
        sendRequestOrNull,
        // wait for response
        (sorobanClient, endpoint) -> endpoint.waitNext(rpcSession));
